import React, { useEffect, useState } from 'react';
import { Button, View, Text, Alert } from 'react-native';

const authConfig = {
  client_id: 'YOUR_CLIENT_ID',
  client_secret: 'YOUR_CLIENT_SECRET',
};

async function getAccessToken(code) {
  const response = await fetch('https://your-oauth-server.com/token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: `grant_type=authorization_code&code=${code}&redirect_uri=https://localhost/callback`,
  });

  const data = await response.json();
  return data.access_token;
}

async function refreshToken(token) {
  const response = await fetch('https://your-oauth-server.com/token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: `grant_type=refresh_token&refresh_token=${token}&client_id=${authConfig.client_id}&client_secret=${authConfig.client_secret}`,
  });

  const data = await response.json();
  return data.access_token;
}

function App() {
  const [login, setLogin] = useState(null);
  const [accessToken, setAccessToken] = useState(null);

  async function handleLogin() {
    try {
      const authUrl = `https://your-oauth-server.com/authorize?response_type=code&client_id=${authConfig.client_id}&redirect_uri=https://localhost/callback`;
      Linking.openURL(authUrl);
    } catch (error) {
      console.error('Error opening URL:', error);
    }
  }

  useEffect(() => {
    const handleLink = async () => {
      try {
        const { code } = await Linking.getInitialURL();
        if (!code) return;

        const accessToken = await getAccessToken(code);
        setAccessToken(accessToken);

        fetch('https://your-oauth-server.com/me', {
          headers: {
            Authorization: `Bearer ${accessToken}`,
          },
        })
          .then((response) => response.json())
          .then((data) => console.log(data))
          .catch((error) => console.error(error));
      } catch (error) {
        console.error('Error handling link:', error);
      }
    };

    Linking.addEventListener('url', handleLink);

    return () => {
      Linking.removeEventListener('url', handleLink);
    };
  }, []);

  useEffect(() => {
    if (!accessToken && authConfig.refresh_token) {
      const accessToken = async () => {
        try {
          const token = await refreshToken(authConfig.refresh_token);
          setAccessToken(token);
        } catch (error) {
          console.error('Error refreshing token:', error);
        }
      };

      accessToken();
    }
  }, [accessToken]);

  return (
    <View>
      {login === 'logged' ? (
        <Text>Logged in with access token: {accessToken}</Text>
      ) : (
        <Button title="Login" onPress={handleLogin} />
      )}
    </View>
  );
}

export default App;